import React, { useState, useEffect } from 'react';
import '../App.css';

const Applications = ({ token }) => {
    const [apps, setApps] = useState([]);
    const [showForm, setShowForm] = useState(false);
    const [form, setForm] = useState({ company: '', position: '', status: 'applied' });
    const [loading, setLoading] = useState(true);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchApps();
    }, []);

    const fetchApps = async () => {
        const res = await fetch('/api/applications', {
            headers: { 'Authorization': token }
        });
        const data = await res.json();
        setApps(data);
        setLoading(false);
    };

    const addApp = async (e) => {
        e.preventDefault();
        const res = await fetch('/api/applications', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': token
            },
            body: JSON.stringify(form)
        });
        if(res.ok){
            setMessage('Application added!');
            setTimeout(() => setMessage(''), 3000);
            setShowForm(false);
            setForm({ company: '', position: '', status: 'applied' });
            fetchApps();
        }
    };

    const deleteApp = async (id) => {
        if(window.confirm('Delete this application?')){
            await fetch(`/api/applications/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': token }
            });
            fetchApps();
        }
    };

    if(loading){
        return <div style={{ textAlign: 'center', padding: '50px' }}>Loading...</div>;
    }

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <h1>Applications</h1>
                <button onClick={() => setShowForm(!showForm)}>
                    {showForm ? 'Cancel' : '+ Add'}
                </button>
            </div>

            {message && <div className="success">{message}</div>}

            {showForm && (
                <div className="card">
                    <h3>New Application</h3>
                    <form onSubmit={addApp}>
                        <input
                            type="text"
                            placeholder="Company"
                            value={form.company}
                            onChange={(e) => setForm({ ...form, company: e.target.value })}
                            required
                        />
                        <input
                            type="text"
                            placeholder="Position"
                            value={form.position}
                            onChange={(e) => setForm({ ...form, position: e.target.value })}
                            required
                        />
                        <select
                            value={form.status}
                            onChange={(e) => setForm({ ...form, status: e.target.value })}
                        >
                            <option value="applied">Applied</option>
                            <option value="interview">Interview</option>
                            <option value="offered">Offered</option>
                            <option value="rejected">Rejected</option>
                        </select>
                        <button type="submit">Save</button>
                    </form>
                </div>
            )}

            <div className="card">
                {apps.length === 0 ? (
                    <p>No applications yet</p>
                ) : (
                    <table>
                        <thead>
                            <tr>
                                <th>Company</th>
                                <th>Position</th>
                                <th>Status</th>
                                <th>Date</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            {apps.map(app => (
                                <tr key={app._id}>
                                    <td>{app.company}</td>
                                    <td>{app.position}</td>
                                    <td><span className={`status status-${app.status}`}>{app.status}</span></td>
                                    <td>{new Date(app.date).toLocaleDateString()}</td>
                                    <td><button onClick={() => deleteApp(app._id)} style={{ background: '#e74c3c' }}>X</button></td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default Applications;
